// theme-styles.js — CSS des thèmes embarqué en JS (évite tout fetch() qui échoue en file://)
const BASE_CSS = "/* _base.css — chargé en plus du thème actif, pour des comportements\n   techniques qu'aucun thème ne devrait avoir à réimplémenter. */\n\n.markdown-body {\n  overflow-wrap: break-word;\n  word-wrap: break-word;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n  text-rendering: optimizeLegibility;\n}\n\n.markdown-body * { box-sizing: border-box; }\n\n.markdown-body img { height: auto; }\n\n/* Un gros tableau scrolle dans sa propre boîte plutôt que de casser la mise en page */\n.markdown-body table {\n  display: block;\n  overflow-x: auto;\n  max-width: 100%;\n}\n\n.markdown-body pre {\n  max-width: 100%;\n  overflow-wrap: normal; /* le code garde ses retours à la ligne propres, scroll horizontal si besoin */\n}\n.markdown-body pre code {\n  white-space: pre;\n}\n\n.markdown-body code {\n  overflow-wrap: break-word;\n}\n\n.markdown-body h1[id], .markdown-body h2[id], .markdown-body h3[id],\n.markdown-body h4[id], .markdown-body h5[id], .markdown-body h6[id] {\n  scroll-margin-top: 24px;\n}\n\n/* Règles d'impression communes — évite qu'un tableau, un bloc de code ou une\n   citation soit coupé au milieu par un saut de page */\n/* Sommaire (TOC) */\n.doc-toc {\n  border: 1px solid rgba(127, 127, 127, 0.35);\n  border-radius: 8px;\n  padding: 16px 20px;\n  margin: 0 0 2em;\n  font-size: 0.9em;\n  opacity: 0.95;\n}\n.doc-toc-title {\n  font-weight: 700;\n  text-transform: uppercase;\n  font-size: 0.78em;\n  letter-spacing: 0.06em;\n  opacity: 0.6;\n  margin-bottom: 0.6em;\n}\n.doc-toc ul { list-style: none; margin: 0; padding-left: 1.1em; }\n.doc-toc > ul { padding-left: 0; }\n.doc-toc li { margin: 0.35em 0; }\n.doc-toc a { text-decoration: none; opacity: 0.85; }\n.doc-toc a:hover { opacity: 1; text-decoration: underline; }\n\n/* Numérotation des sections */\n.heading-num {\n  opacity: 0.55;\n  font-weight: 600;\n  margin-right: 0.15em;\n}\n\n@media print {\n  .markdown-body pre,\n  .markdown-body table,\n  .markdown-body blockquote,\n  .markdown-body img {\n    break-inside: avoid;\n  }\n  .markdown-body h1, .markdown-body h2, .markdown-body h3,\n  .markdown-body h4, .markdown-body h5, .markdown-body h6 {\n    break-after: avoid;\n  }\n  .doc-toc { break-after: page; }\n}\n";

