  personnalise: "/* personnalise.css — thème \"Personnalisé\", piloté par variables CSS\n   (--ct-*) plutôt que des couleurs figées comme les autres thèmes.\n   Les valeurs réelles sont injectées par js/theme-editor.js dans un\n   <style id=\"custom-theme-vars\"> sur :root ; les valeurs par défaut\n   ci-dessous (2e argument de chaque var()) ne servent que tant que\n   l'utilisateur n'a encore rien personnalisé. */\n\n.markdown-body {\n  font-family: -apple-system, 'Segoe UI', Helvetica, Arial, sans-serif;\n  font-size: 16px;\n  line-height: 1.7;\n  color: var(--ct-text, #2b2720);\n  background: var(--ct-bg, #ffffff);\n  max-width: 760px;\n  margin: 0 auto;\n  padding: 4px 0 20px;\n}\n.markdown-body h1, .markdown-body h2, .markdown-body h3,\n.markdown-body h4, .markdown-body h5, .markdown-body h6 {\n  color: var(--ct-heading, #16130f);\n  font-weight: 700;\n}\n.markdown-body h1 { font-size: 1.9em; border-bottom: 2px solid var(--ct-heading, #16130f); padding-bottom: 0.3em; }\n.markdown-body h2 { font-size: 1.45em; margin-top: 1.7em; }\n.markdown-body h3 { font-size: 1.15em; margin-top: 1.4em; }\n.markdown-body a { color: var(--ct-link, #0969da); text-decoration: underline; }\n.markdown-body strong { color: var(--ct-heading, #16130f); }\n.markdown-body code {\n  font-family: 'JetBrains Mono', monospace;\n  font-size: 0.85em;\n  background: var(--ct-code-bg, #f6f8fa);\n  color: var(--ct-code-text, #c8393a);\n  padding: 0.15em 0.4em;\n  border-radius: 4px;\n}\n.markdown-body pre {\n  background: var(--ct-pre-bg, #0d1117);\n  padding: 14px 16px;\n  border-radius: 8px;\n  overflow-x: auto;\n}\n.markdown-body pre code { background: transparent; color: var(--ct-pre-text, #e6edf3); padding: 0; }\n.markdown-body blockquote {\n  border-left: 3px solid var(--ct-quote-border, #d0d7de);\n  margin: 1.3em 0;\n  padding: 0.1em 0 0.1em 1.1em;\n  color: var(--ct-quote-text, #57606a);\n  font-style: italic;\n}\n.markdown-body table { border-collapse: collapse; width: 100%; margin: 1.4em 0; }\n.markdown-body th, .markdown-body td { border: 1px solid var(--ct-table-border, #d0d7de); padding: 7px 12px; }\n.markdown-body th { background: var(--ct-code-bg, #f6f8fa); }\n.markdown-body img { max-width: 100%; border-radius: 6px; }\n.markdown-body hr { border: none; border-top: 1px solid var(--ct-table-border, #d0d7de); margin: 2.2em 0; }\n.markdown-body .doc-toc { border-color: var(--ct-table-border, #d0d7de); }\n.markdown-body .heading-num { color: var(--ct-link, #0969da); }\n",
  cyberpunk: ".markdown-body {\n  font-family: 'JetBrains Mono', monospace;\n  font-size: 15px;\n  line-height: 1.7;\n  color: #d5f5ec;\n  background: #0b0f14;\n  max-width: 780px;\n  margin: 0 auto;\n  min-height: 100%;\n  padding-bottom: 60px;\n}\n.markdown-body h1, .markdown-body h2, .markdown-body h3 {\n  color: #5eead4;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n}\n.markdown-body h1 { border-bottom: 1px solid #234; padding-bottom: 0.3em; font-size: 1.7em; }\n.markdown-body h2 { font-size: 1.3em; margin-top: 1.8em; }\n.markdown-body a { color: #ff6b9d; }\n.markdown-body code {\n  background: #131a22;\n  color: #5eead4;\n  padding: 0.15em 0.4em;\n  border-radius: 2px;\n  border: 1px solid #234;\n}\n.markdown-body pre {\n  background: #131a22;\n  border: 1px solid #234;\n  padding: 14px 16px;\n  overflow-x: auto;\n}\n.markdown-body pre code { background: transparent; border: none; padding: 0; }\n.markdown-body blockquote {\n  border-left: 3px solid #5eead4;\n  margin: 1em 0;\n  padding: 0 1em;\n  color: #8fa;\n  opacity: 0.75;\n}\n.markdown-body table { border-collapse: collapse; width: 100%; margin: 1em 0; }\n.markdown-body th, .markdown-body td { border: 1px solid #234; padding: 6px 12px; }\n.markdown-body th { color: #5eead4; }\n.markdown-body img { max-width: 100%; filter: saturate(1.1); }\n.markdown-body hr { border: none; border-top: 1px dashed #234; margin: 2em 0; }\n",
